sql:
SELECT COUNT(product_id) AS total_active_products
FROM products
WHERE is_active = 1;

SELECT product_name, COUNT(DISTINCT product_family) AS family_count
FROM products
GROUP BY product_name;

SELECT vendor_name, contact_email, COUNT(*) OVER () AS total_preferred_vendors, is_preferred
FROM vendors
WHERE is_preferred = 1;

external_knowledge:
- 'detailed product information' refers to product name, description, family, vendor details, and performance rating; 
- 'vendors' performance' refers to the number of requests, latest request due date, and completion rate; 
- 'families' statistics' refers to the number of products in the family and the ratio of active products in the family; 
- 'associated requests count' refers to the number of distinct requests associated with each product's vendor.
